customHandlers.hongguoListHandler:
function(ctx) {
    let proxy = 'http://localhost:3000/?url=';
    let apiUrl = `https://api.cenguigui.cn/api/duanju/api.php?type=search&name=&page=${ctx.pg || 1}`;
    let resp = req(proxy + encodeURIComponent(apiUrl));
    let content = resp.text ? resp.text() : (typeof resp === 'string' ? resp : '');
    let json = JSON.parse(content);
    let list = json.data || [];
    return list.map(item => ({
        vod_id: `###${item.book_id}###${item.book_name}`,
        vod_name: item.book_name,
        vod_pic: item.book_pic || ''
    }));
}

customHandlers.hongguoDetailHandler:
function(ctx) {
    let proxy = 'http://localhost:3000/?url=';
    let parts = ctx.vodId.split('###');
    let bookId = parts[1];
    let title = parts[2];
    if (!bookId) return { list: [] };
    let apiUrl = `https://api.cenguigui.cn/api/duanju/api.php?type=detail&book_id=${bookId}`;
    let resp = req(proxy + encodeURIComponent(apiUrl));
    let content = resp.text ? resp.text() : (typeof resp === 'string' ? resp : '');
    let json = JSON.parse(content);
    let videoArr = json.data || [];
    let videoList = [];
    for (let i = 0; i < videoArr.length; i++) {
        let video = videoArr[i];
        let sortName = video.sort || ('第' + (i+1) + '集');
        videoList.push(`${sortName}$${video.video_id}`);
    }
    let vod = {
        vod_id: ctx.vodId,
        vod_name: title,
        vod_play_from: '红果短剧',
        vod_play_url: videoList.join('#')
    };
    return { list: [vod] };
}

customHandlers.hongguoPlayHandler:
function(ctx) {
    let proxy = 'http://localhost:3000/?url=';
    let videoId = ctx.id;
    let apiUrl = `https://api.cenguigui.cn/api/duanju/api.php?type=video&video_id=${videoId}`;
    let resp = req(proxy + encodeURIComponent(apiUrl));
    let content = resp.text ? resp.text() : (typeof resp === 'string' ? resp : '');
    let json = JSON.parse(content);
    let playUrl = json.url || json.data || '';
    return { parse: 0, playUrl: '', url: playUrl };
}
